// ============================================================
//  api.js  —  works with Spring Boot ApiResponse<T> wrapper
//  Exports BOTH named functions (for your existing pages)
//  AND grouped objects (authAPI, eventAPI, etc.)
// ============================================================

const BASE_URL = 'http://localhost:8080/api';

const getHeaders = () => {
  const token = localStorage.getItem('token');
  return {
    'Content-Type': 'application/json',
    ...(token && { Authorization: `Bearer ${token}` }),
  };
};

// Spring Boot returns ApiResponse<T> { message, data, success }
// This unwraps .data automatically
const unwrap = (json) => {
  if (json && typeof json === 'object' && 'data' in json) return json.data;
  return json;
};

const request = async (method, path, body = null) => {
  const url = `${BASE_URL}${path}`;
  console.log(`[API] ${method} ${url}`, body ?? '');

  let res;
  try {
    res = await fetch(url, {
      method,
      headers: getHeaders(),
      ...(body !== null && { body: JSON.stringify(body) }),
    });
  } catch (networkErr) {
    console.error('[API] Network error:', networkErr);
    throw new Error('Cannot connect to server. Is Spring Boot running on port 8080?');
  }

  console.log(`[API] ${res.status} <- ${url}`);

  if (res.status === 401) {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    window.location.href = '/login';
    throw new Error('Session expired. Please login again.');
  }

  if (!res.ok) {
    let errMsg = `Server error (${res.status})`;
    try {
      const errBody = await res.json();
      errMsg = errBody.message || errBody.error || errMsg;
    } catch {
      try { errMsg = await res.text() || errMsg; } catch {}
    }
    console.error(`[API] Error ${res.status}:`, errMsg);
    throw new Error(errMsg);
  }

  if (res.status === 204) return null;

  try {
    const json = await res.json();
    return unwrap(json);
  } catch {
    return null;
  }
};

const getStoredUser = () => {
  try { return JSON.parse(localStorage.getItem('user')); } catch { return null; }
};


// ─────────────────────────────────────────────────────────────
//  AUTH
// ─────────────────────────────────────────────────────────────
export const loginUser       = (data) => request('POST', '/auth/login', data);
export const registerUser    = (data) => request('POST', '/auth/register', data);
export const checkEmail      = (email) => request('GET', `/auth/check-email?email=${encodeURIComponent(email)}`).catch(() => ({ exists: false }));

export const authAPI = { login: loginUser, register: registerUser, checkEmail };


// ─────────────────────────────────────────────────────────────
//  EVENTS
//  Controller: GET /api/events, /api/events/filter,
//              /api/events/{id}, /api/events/organiser/{id},
//              POST /api/events, PUT /api/events/{id},
//              DELETE /api/events/{id}, GET /api/events/search
// ─────────────────────────────────────────────────────────────
export const getAllEvents = (sortBy) => {
  const q = sortBy ? `?sortBy=${sortBy}` : '';
  return request('GET', `/events${q}`);
};

export const filterEvents = ({ type, genre, language, status, name } = {}) => {
  const params = new URLSearchParams();
  if (type)     params.append('type', type);
  if (genre)    params.append('genre', genre);
  if (language) params.append('language', language);
  if (status)   params.append('status', status);
  if (name)     params.append('name', name);
  const q = params.toString();
  return request('GET', `/events/filter${q ? '?' + q : ''}`);
};

export const getEventById = (id) => request('GET', `/events/${id}`);

export const getEventsByOrganiser = (organiserId) =>
  request('GET', `/events/organiser/${organiserId}`);

export const searchEvents = (name) =>
  request('GET', `/events/search?name=${encodeURIComponent(name)}`);

export const createEvent = (data) => {
  const user = getStoredUser();
  return request('POST', '/events', { ...data, organiserId: user?.userId });
};

export const updateEvent = (id, data) => request('PUT', `/events/${id}`, data);

export const deleteEvent = (id) => request('DELETE', `/events/${id}`);

export const eventAPI = {
  getAll: getAllEvents,
  filter: filterEvents,
  getById: getEventById,
  getMyEvents: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return getEventsByOrganiser(user.userId);
  },
  getByOrganiser: getEventsByOrganiser,
  search: searchEvents,
  create: createEvent,
  update: updateEvent,
  delete: deleteEvent,
};


// ─────────────────────────────────────────────────────────────
//  SHOW SLOTS
//  Adjust paths if your ShowSlotController uses different URLs
// ─────────────────────────────────────────────────────────────
export const getSlotsByEvent = (eventId) =>
  request('GET', `/show-slots/event/${eventId}`);

export const getSlotById = (id) =>
  request('GET', `/show-slots/${id}`);

export const createSlot = (data) => request('POST', '/show-slots', data);

export const updateSlot = (id, data) => request('PUT', `/show-slots/${id}`, data);

export const deleteSlot = (id) => request('DELETE', `/show-slots/${id}`);

export const slotAPI = {
  getByEvent: getSlotsByEvent,
  getById: getSlotById,
  create: createSlot,
  update: updateSlot,
  delete: deleteSlot,
};


// ─────────────────────────────────────────────────────────────
//  LOCATIONS
// ─────────────────────────────────────────────────────────────
export const getAllLocations  = () => request('GET', '/locations');
export const getLocationById  = (id) => request('GET', `/locations/${id}`);
export const createLocation   = (data) => request('POST', '/locations', data);
export const deleteLocation   = (id) => request('DELETE', `/locations/${id}`);

export const locationAPI = {
  getAll: getAllLocations,
  getById: getLocationById,
  create: createLocation,
  delete: deleteLocation,
};


// ─────────────────────────────────────────────────────────────
//  SEATS  (seat-slots = seats assigned to a show slot)
// ─────────────────────────────────────────────────────────────
export const getSeatsByLocation  = (locationId) =>
  request('GET', `/seats/location/${locationId}`);

export const getAvailableSeats   = (slotId) =>
  request('GET', `/seat-slots/slot/${slotId}`);

export const createSeat = (data) => request('POST', '/seats', data);
export const updateSeat = (id, data) => request('PUT', `/seats/${id}`, data);
export const deleteSeat = (id) => request('DELETE', `/seats/${id}`);

export const seatAPI = {
  getByLocation: getSeatsByLocation,
  getBySlot: getAvailableSeats,
  create: createSeat,
  update: updateSeat,
  delete: deleteSeat,
};


// ─────────────────────────────────────────────────────────────
//  RESERVATIONS (BOOKINGS)
// ─────────────────────────────────────────────────────────────
export const bookSeats = (data) => request('POST', '/reservations', data);

export const getReservationsByUser = (userId) =>
  request('GET', `/reservations/user/${userId}`);

export const getReservationsByOrganiser = (organiserId) =>
  request('GET', `/reservations/organiser/${organiserId}`);

export const getReservationById = (id) =>
  request('GET', `/reservations/${id}`);

export const cancelReservation = (id, reason) =>
  request('POST', `/reservations/${id}/cancel`, { reason });

export const getAllReservations = () => request('GET', '/reservations');

export const reservationAPI = {
  create: bookSeats,
  getByUser: getReservationsByUser,
  getByOrganiser: getReservationsByOrganiser,
  getById: getReservationById,
  cancel: cancelReservation,
  getAll: getAllReservations,
  getMyReservations: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return getReservationsByUser(user.userId);
  },
};


// ─────────────────────────────────────────────────────────────
//  TRANSACTIONS (PAYMENTS)
// ─────────────────────────────────────────────────────────────
export const processPayment = (data) => request('POST', '/transactions', data);

export const getTransactionsByOrganiser = (organiserId) =>
  request('GET', `/transactions/organiser/${organiserId}`);

export const getTransactionsByUser = (userId) =>
  request('GET', `/transactions/user/${userId}`);

export const getAllTransactions = () => request('GET', '/transactions');

export const getTransactionByReservation = (resId) =>
  request('GET', `/transactions/reservation/${resId}`);

export const transactionAPI = {
  processPayment,
  getByOrganiser: getTransactionsByOrganiser,
  getByUser: getTransactionsByUser,
  getAll: getAllTransactions,
  getByReservation: getTransactionByReservation,
  getMyTransactions: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return getTransactionsByUser(user.userId);
  },
};


// ─────────────────────────────────────────────────────────────
//  CANCELLATIONS
// ─────────────────────────────────────────────────────────────
export const getAllCancellations = () =>
  request('GET', '/cancellations');

export const getCancellationsByOrganiser = (organiserId) =>
  request('GET', `/cancellations/organiser/${organiserId}`);

export const updateRefundStatus = (cancellationId, status) =>
  request('PUT', `/cancellations/${cancellationId}/refund`, { refundStatus: status });


// ─────────────────────────────────────────────────────────────
//  NOTIFICATIONS
// ─────────────────────────────────────────────────────────────
export const getNotificationsByUser = (userId) =>
  request('GET', `/notifications/user/${userId}`);

export const markNotificationRead = (id) =>
  request('PUT', `/notifications/${id}/read`);

export const sendBulkNotification = (data) =>
  request('POST', '/notifications/send-bulk', data);

export const sendReminders = (slotId) =>
  request('POST', `/notifications/remind/${slotId}`);

export const notificationAPI = {
  getByUser: getNotificationsByUser,
  markRead: markNotificationRead,
  sendBulk: sendBulkNotification,
  sendReminders,
  getMyNotifications: () => {
    const user = getStoredUser();
    if (!user?.userId) return Promise.resolve([]);
    return getNotificationsByUser(user.userId);
  },
